mapper.update:
UPDATE inspection_request
SET inspection_state = #{inspectionState}
WHERE id = #{id}

mapper.select:
SELECT ir.register_id AS registerId, 'INSPECTION' AS itemType, mt.tech_name AS itemName, ir.id AS itemId, mt.tech_price AS amount, ir.inspection_state AS orderState, d.dept_name AS deptName, r.visit_date AS visitDate, ir.creation_time AS createTime, NULL AS payTime FROM inspection_request ir LEFT JOIN register r ON ir.register_id = r.id LEFT JOIN department d ON r.deptment_id = d.id LEFT JOIN medical_technology mt ON ir.medical_technology_id = mt.id WHERE r.patient_id = #{patientId} AND mt.tech_price IS NOT NULL AND mt.tech_price > 0
AND ir.inspection_state = #{orderState}
ORDER BY ir.creation_time DESC LIMIT #{limit} OFFSET #{offset}
